<template><ContentWrap><el-button class="mb-10px" @click="openCreate">{{ t('common.create') }}</el-button><el-table v-loading="loading" :data="list"><el-table-column prop="code" :label="t('crm.marketing.code')" /><el-table-column prop="name" :label="t('crm.marketing.name')" /><el-table-column prop="ruleType" :label="t('crm.marketing.ruleType')" /><el-table-column prop="eventMonthDay" :label="t('crm.marketing.eventMonthDay')" /><el-table-column prop="channel" :label="t('crm.marketing.channel')" /><el-table-column prop="enabled" :label="t('crm.marketing.enabled')" /></el-table><Pagination v-model:page="query.pageNo" v-model:limit="query.pageSize" :total="total" @pagination="reload" /><el-dialog v-model="dialogVisible" :title="t('crm.marketing.createCarePlan')"><el-form :model="form" label-width="110px"><el-form-item :label="t('crm.marketing.code')"><el-input v-model="form.code" /></el-form-item><el-form-item :label="t('crm.marketing.name')"><el-input v-model="form.name" /></el-form-item><el-form-item :label="t('crm.marketing.ruleType')"><el-select v-model="form.ruleType"><el-option :label="t('crm.marketing.birthday')" :value="1" /><el-option :label="t('crm.marketing.holiday')" :value="2" /></el-select></el-form-item><el-form-item :label="t('crm.marketing.eventMonthDay')"><el-input v-model="form.eventMonthDay" placeholder="MM-dd" /></el-form-item><el-form-item :label="t('crm.marketing.channel')"><el-select v-model="form.channel"><el-option :label="t('crm.marketing.sms')" :value="1" /><el-option :label="t('crm.marketing.email')" :value="2" /><el-option :label="t('crm.marketing.both')" :value="3" /></el-select></el-form-item><el-form-item :label="t('crm.marketing.smsTemplateCode')"><el-input v-model="form.smsTemplateCode" /></el-form-item><el-form-item :label="t('crm.marketing.mailTemplateCode')"><el-input v-model="form.mailTemplateCode" /></el-form-item><el-form-item :label="t('crm.marketing.enabled')"><el-switch v-model="form.enabled" /></el-form-item></el-form><template #footer><el-button @click="dialogVisible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="save">{{ t('common.ok') }}</el-button></template></el-dialog></ContentWrap></template>
<script setup lang="ts">import {ref,reactive} from 'vue';import {useI18n} from '@/hooks/web/useI18n';import * as Api from '@/api/crm/marketing';const{t}=useI18n();const loading=ref(false),list=ref<any[]>([]),total=ref(0),dialogVisible=ref(false);const query=reactive({pageNo:1,pageSize:10});const form=reactive<any>({code:'',name:'',ruleType:1,eventMonthDay:'01-01',channel:1,smsTemplateCode:'',mailTemplateCode:'',enabled:false});const reload=async()=>{loading.value=true;try{const r=await Api.getCarePlanPage(query);list.value=r.list||[];total.value=r.total||0}finally{loading.value=false}};const openCreate=()=>{Object.assign(form,{code:'',name:'',ruleType:1,eventMonthDay:'01-01',channel:1,smsTemplateCode:'',mailTemplateCode:'',enabled:false});dialogVisible.value=true};const save=async()=>{await Api.saveCarePlan(form);dialogVisible.value=false;reload()};reload()</script>
